import React, { useState } from "react";

const Navbar = ({ onSearch, onCategoryChange }) => {

  // 🔹 Categories (TOP pe define)
  const categories = ["All", "Personal", "Work", "Study", "Health", "Finance"];

  // 🔹 Time-based greeting
  const getGreeting = () => {
    const hour = new Date().getHours();
    if (hour < 12) return "Good morning";
    if (hour < 18) return "Good afternoon";
    return "Good evening";
  };

  // 🔹 State
  const [search, setSearch] = useState("");
  const [selectedCategory, setSelectedCategory] = useState("All");

  // 🔹 Static user
  const user = {
    name: "Priyanshu",
    isLoggedIn: true
  };

  // 🔹 Search handler
  const handleSearch = (e) => {
    const value = e.target.value;
    setSearch(value);
    onSearch && onSearch(value);
  };

  // 🔹 Category handler
  const handleCategory = (cat) => {
    setSelectedCategory(cat);
    onCategoryChange && onCategoryChange(cat);
  };

  return (
    <div className="bg-gradient-to-br from-[#141E30] to-[#243B55] flex justify-center p-6">

      <div className="w-full space-y-4">

        {/* 🔹 Header */}
        <div className="flex items-center justify-between bg-white/10 backdrop-blur-xl border border-white/20 rounded-2xl px-6 py-4 shadow-lg">

          {/* Left */}
          <div>
            <h1 className="text-2xl font-semibold text-white">
              👋 {getGreeting()}, {user.name}
            </h1>

            <p className="text-sm text-white/70">
              Be efficient, be productive.
            </p>
          </div>

          {/* Right */}
          <div className="flex items-center gap-4">

            <div className="flex items-center gap-3 bg-white/10 px-3 py-2 rounded-xl border border-white/20">
              <img
                src="https://i.pravatar.cc/40"
                className="w-9 h-9 rounded-full"
                alt=""
              />
              <span className="text-white text-sm">{user.name}</span>
            </div>

            <button className="px-5 py-2 rounded-xl bg-gradient-to-r from-red-500 to-pink-500 text-white">
              Logout
            </button>

          </div>
        </div>

        {/* 🔥 Search */}
        <input
          type="text"
          placeholder="Search tasks..."
          value={search}
          onChange={handleSearch}
          className="w-full px-4 py-3 rounded-xl bg-white/10 border border-white/20 text-white placeholder-white/60 focus:outline-none focus:ring-2 focus:ring-white/30"
        />

        {/* 🔥 Categories (Buttons style) */}
        <div className="flex flex-wrap gap-3">

          {categories.map((cat, i) => (
            <button
              key={i}
              onClick={() => handleCategory(cat)}
              className={`px-4 py-2 rounded-full text-sm transition ${
                selectedCategory === cat
                  ? "bg-white text-black"
                  : "bg-white/10 text-white hover:bg-white/20"
              }`}
            >
              {cat}
            </button>
          ))}

        </div>

      </div>
    </div>
  );
};

export default Navbar;
